module RefModule(
    input clk,          // Clock signal.
    input en,           // Enable signal.
    output reg [3:0] q  // 4-bit counter output.
);

// Counter logic
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (en)
        q <= q + 1;     // Increment counter if enable is active
end

endmodule
